((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='japanese'), 'jp_j_11', '"日本"의 읽기는?', '["니혼","닛폰","둘 다 맞음","니치혼"]', 2, '두 가지 읽기 모두 맞습니다.', 11),
